CREATE OR REPLACE FUNCTION ledger.get_balance(p_year integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_year integer;
  v_start date;
  v_end date;
  v_body text;
  v_rows text[];
  v_total_debit numeric := 0;
  v_total_credit numeric := 0;
  r record;
BEGIN
  v_year := coalesce(p_year, extract(year FROM CURRENT_DATE)::integer);
  v_start := make_date(v_year, 1, 1);
  v_end := make_date(v_year, 12, 31);

  v_body := pgv.breadcrumb(VARIADIC ARRAY['Balance de vérification']);

  -- Year selector
  v_body := v_body || '<div class="grid">'
    || format('<a href="%s" role="button" class="outline">%s</a>', pgv.call_ref('get_balance', jsonb_build_object('p_year', v_year - 1)), (v_year - 1)::text)
    || format('<a href="%s" role="button">%s</a>', pgv.call_ref('get_balance', jsonb_build_object('p_year', v_year)), v_year::text)
    || format('<a href="%s" role="button" class="outline">%s</a>', pgv.call_ref('get_balance', jsonb_build_object('p_year', v_year + 1)), (v_year + 1)::text)
    || '</div>';

  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT a.code, a.label, a.type,
           coalesce(sum(el.debit), 0) AS total_debit,
           coalesce(sum(el.credit), 0) AS total_credit
      FROM ledger.account a
      LEFT JOIN ledger.entry_line el ON el.account_id = a.id
        AND EXISTS (SELECT 1 FROM ledger.journal_entry je
                     WHERE je.id = el.journal_entry_id AND je.posted = true
                       AND je.entry_date >= v_start AND je.entry_date <= v_end)
     WHERE a.active
     GROUP BY a.id, a.code, a.label, a.type
    HAVING coalesce(sum(el.debit), 0) <> 0 OR coalesce(sum(el.credit), 0) <> 0
     ORDER BY a.code
  LOOP
    v_total_debit := v_total_debit + r.total_debit;
    v_total_credit := v_total_credit + r.total_credit;
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_grand_livre', jsonb_build_object('p_account_id', (SELECT id FROM ledger.account WHERE code = r.code), 'p_year', v_year)), pgv.esc(r.code)),
      pgv.esc(r.label),
      to_char(r.total_debit, 'FM999 990.00') || ' €',
      to_char(r.total_credit, 'FM999 990.00') || ' €',
      to_char(r.total_debit - r.total_credit, 'FM999 990.00') || ' €'
    ];
  END LOOP;

  -- Stats
  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.stat('Total débit', to_char(v_total_debit, 'FM999 990.00') || ' €'),
    pgv.stat('Total crédit', to_char(v_total_credit, 'FM999 990.00') || ' €'),
    pgv.stat('Écart', to_char(v_total_debit - v_total_credit, 'FM999 990.00') || ' €',
      CASE WHEN v_total_debit = v_total_credit THEN 'Équilibre OK' ELSE 'DÉSÉQUILIBRE' END)
  ]);

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucun mouvement sur ' || v_year);
  ELSE
    v_body := v_body || pgv.md_table(
      ARRAY['Code', 'Libellé', 'Débit', 'Crédit', 'Solde'],
      v_rows, 20
    );
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_balance(integer) IS 'Balance de vérification : total débit/crédit/solde par compte, avec filtres année';

CREATE OR REPLACE FUNCTION ledger.get_bilan(p_year integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_year integer;
  v_start date;
  v_end date;
  v_body text;
  v_rows_r text[];
  v_rows_e text[];
  v_total_revenue numeric := 0;
  v_total_expense numeric := 0;
  v_resultat numeric;
  r record;
BEGIN
  v_year := coalesce(p_year, extract(year FROM CURRENT_DATE)::integer);
  v_start := make_date(v_year, 1, 1);
  v_end := make_date(v_year, 12, 31);

  v_body := pgv.breadcrumb(VARIADIC ARRAY['Bilan']);

  -- Sélecteur année
  v_body := v_body || '<div class="grid">'
    || format('<a href="%s" role="button" class="outline">%s</a>', pgv.call_ref('get_bilan', jsonb_build_object('p_year', v_year - 1)), (v_year - 1)::text)
    || format('<a href="%s" role="button">%s</a>', pgv.call_ref('get_bilan', jsonb_build_object('p_year', v_year)), v_year::text)
    || format('<a href="%s" role="button" class="outline">%s</a>', pgv.call_ref('get_bilan', jsonb_build_object('p_year', v_year + 1)), (v_year + 1)::text)
    || '</div>';

  -- Produits (revenue = classe 7)
  v_rows_r := ARRAY[]::text[];
  FOR r IN
    SELECT a.code, a.label,
           coalesce(sum(el.credit) - sum(el.debit), 0) AS balance
      FROM ledger.account a
      LEFT JOIN ledger.entry_line el ON el.account_id = a.id
        AND EXISTS (SELECT 1 FROM ledger.journal_entry je
                     WHERE je.id = el.journal_entry_id AND je.posted = true
                       AND je.entry_date >= v_start AND je.entry_date <= v_end)
     WHERE a.type = 'revenue' AND a.active
     GROUP BY a.id, a.code, a.label
     ORDER BY a.code
  LOOP
    v_total_revenue := v_total_revenue + r.balance;
    IF r.balance <> 0 THEN
      v_rows_r := v_rows_r || ARRAY[
        pgv.esc(r.code), pgv.esc(r.label),
        to_char(r.balance, 'FM999 990.00') || ' €'
      ];
    END IF;
  END LOOP;

  -- Charges (expense = classe 6)
  v_rows_e := ARRAY[]::text[];
  FOR r IN
    SELECT a.code, a.label,
           coalesce(sum(el.debit) - sum(el.credit), 0) AS balance
      FROM ledger.account a
      LEFT JOIN ledger.entry_line el ON el.account_id = a.id
        AND EXISTS (SELECT 1 FROM ledger.journal_entry je
                     WHERE je.id = el.journal_entry_id AND je.posted = true
                       AND je.entry_date >= v_start AND je.entry_date <= v_end)
     WHERE a.type = 'expense' AND a.active
     GROUP BY a.id, a.code, a.label
     ORDER BY a.code
  LOOP
    v_total_expense := v_total_expense + r.balance;
    IF r.balance <> 0 THEN
      v_rows_e := v_rows_e || ARRAY[
        pgv.esc(r.code), pgv.esc(r.label),
        to_char(r.balance, 'FM999 990.00') || ' €'
      ];
    END IF;
  END LOOP;

  v_resultat := v_total_revenue - v_total_expense;

  -- Stats résumé
  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.stat('Produits', to_char(v_total_revenue, 'FM999 990.00') || ' €'),
    pgv.stat('Charges', to_char(v_total_expense, 'FM999 990.00') || ' €'),
    pgv.stat('Résultat net', to_char(v_resultat, 'FM999 990.00') || ' €',
      CASE WHEN v_resultat >= 0 THEN 'Bénéfice' ELSE 'Déficit' END)
  ]);

  -- Tables détail
  v_body := v_body || pgv.tabs(VARIADIC ARRAY[
    'Produits (classe 7)',
    CASE WHEN array_length(v_rows_r, 1) IS NULL
      THEN pgv.empty('Aucun produit sur ' || v_year)
      ELSE pgv.md_table(ARRAY['Code', 'Libellé', 'Montant'], v_rows_r)
        || '<p><strong>Total produits : ' || to_char(v_total_revenue, 'FM999 990.00') || ' €</strong></p>'
    END,
    'Charges (classe 6)',
    CASE WHEN array_length(v_rows_e, 1) IS NULL
      THEN pgv.empty('Aucune charge sur ' || v_year)
      ELSE pgv.md_table(ARRAY['Code', 'Libellé', 'Montant'], v_rows_e)
        || '<p><strong>Total charges : ' || to_char(v_total_expense, 'FM999 990.00') || ' €</strong></p>'
    END
  ]);

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_bilan(integer) IS 'Bilan P&L : produits vs charges par compte, résultat net. Filtre par année.';

CREATE OR REPLACE FUNCTION ledger.get_entries()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_rows text[];
  v_body text;
  r record;
BEGIN
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT je.id, je.entry_date, je.reference, je.description, je.posted,
           coalesce(sum(el.debit), 0) AS total_debit
      FROM ledger.journal_entry je
      LEFT JOIN ledger.entry_line el ON el.journal_entry_id = je.id
     GROUP BY je.id
     ORDER BY je.entry_date DESC, je.id DESC
  LOOP
    v_rows := v_rows || ARRAY[
      to_char(r.entry_date, 'DD/MM/YYYY'),
      format('<a href="%s">%s</a>', pgv.call_ref('get_entry', jsonb_build_object('p_id', r.id)), pgv.esc(r.reference)),
      pgv.esc(r.description),
      to_char(r.total_debit, 'FM999 990.00') || ' €',
      CASE WHEN r.posted THEN pgv.badge('Validée', 'success') ELSE pgv.badge('Brouillon', 'warning') END
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := pgv.empty('Aucune écriture', 'Créez votre première écriture comptable.');
  ELSE
    v_body := pgv.md_table(
      ARRAY['Date', 'Référence', 'Description', 'Montant', 'Statut'],
      v_rows, 15
    );
  END IF;

  v_body := v_body || format('<p><a href="%s" role="button">Nouvelle écriture</a></p>', pgv.call_ref('get_entry_form'));

  RETURN pgv.breadcrumb(VARIADIC ARRAY['Écritures']) || v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_entries() IS 'Journal des écritures : table paginée avec statut';

CREATE OR REPLACE FUNCTION ledger.get_entry(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_entry record;
  v_body text;
  v_rows text[];
  v_total_debit numeric := 0;
  v_total_credit numeric := 0;
  v_balanced boolean;
  v_accounts_options text;
  r record;
BEGIN
  SELECT * INTO v_entry FROM ledger.journal_entry WHERE id = p_id;
  IF NOT FOUND THEN RETURN pgv.empty('Écriture introuvable'); END IF;

  v_body := pgv.breadcrumb(VARIADIC ARRAY[
    'Écritures', pgv.call_ref('get_entries'),
    v_entry.reference
  ]);

  v_body := v_body || pgv.dl(VARIADIC ARRAY[
    'Date', to_char(v_entry.entry_date, 'DD/MM/YYYY'),
    'Référence', pgv.esc(v_entry.reference),
    'Description', pgv.esc(v_entry.description),
    'Statut', CASE WHEN v_entry.posted THEN pgv.badge('Validée', 'success') ELSE pgv.badge('Brouillon', 'warning') END
  ]);

  -- Lignes
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT el.id, el.account_id, a.code, a.label AS account_label,
           el.debit, el.credit, el.label
      FROM ledger.entry_line el
      JOIN ledger.account a ON a.id = el.account_id
     WHERE el.journal_entry_id = p_id
     ORDER BY el.id
  LOOP
    v_total_debit := v_total_debit + r.debit;
    v_total_credit := v_total_credit + r.credit;
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s</a> %s', pgv.call_ref('get_account', jsonb_build_object('p_id', r.account_id)), pgv.esc(r.code), pgv.esc(r.account_label)),
      pgv.esc(r.label),
      CASE WHEN r.debit > 0 THEN to_char(r.debit, 'FM999 990.00') ELSE '' END,
      CASE WHEN r.credit > 0 THEN to_char(r.credit, 'FM999 990.00') ELSE '' END,
      CASE WHEN NOT v_entry.posted
        THEN pgv.action('post_line_delete', 'Suppr.', jsonb_build_object('id', r.id, 'entry_id', p_id), 'Supprimer cette ligne ?', 'danger')
        ELSE ''
      END
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucune ligne', 'Ajoutez des lignes à cette écriture.');
  ELSE
    -- Add totals row
    v_rows := v_rows || ARRAY[
      '<strong>Total</strong>', '',
      '<strong>' || to_char(v_total_debit, 'FM999 990.00') || '</strong>',
      '<strong>' || to_char(v_total_credit, 'FM999 990.00') || '</strong>',
      ''
    ];
    v_body := v_body || pgv.md_table(
      ARRAY['Compte', 'Libellé', 'Débit', 'Crédit', ''],
      v_rows
    );
  END IF;

  -- Alert si déséquilibrée
  v_balanced := ledger._entry_balanced(p_id);
  IF NOT v_balanced AND v_total_debit + v_total_credit > 0 THEN
    v_body := v_body || pgv.alert(
      'Écriture déséquilibrée : débit ' || to_char(v_total_debit, 'FM999 990.00')
        || ' € ≠ crédit ' || to_char(v_total_credit, 'FM999 990.00') || ' €',
      'danger'
    );
  END IF;

  -- Formulaire ajout ligne (brouillon uniquement)
  IF NOT v_entry.posted THEN
    -- Build account options
    v_accounts_options := '';
    FOR r IN SELECT id, code, label FROM ledger.account WHERE active ORDER BY code LOOP
      v_accounts_options := v_accounts_options
        || '<option value="' || r.id || '">' || pgv.esc(r.code) || ' — ' || pgv.esc(r.label) || '</option>';
    END LOOP;

    v_body := v_body || '<details><summary>Ajouter une ligne</summary>'
      || '<form data-rpc="post_line_add">'
      || '<input type="hidden" name="entry_id" value="' || p_id || '">'
      || '<label>Compte <select name="account_id" required>'
      || '<option value="">— Choisir —</option>'
      || v_accounts_options
      || '</select></label>'
      || '<div class="grid">'
      || '<label>Débit <input type="number" name="debit" value="0" step="0.01" min="0"></label>'
      || '<label>Crédit <input type="number" name="credit" value="0" step="0.01" min="0"></label>'
      || '</div>'
      || '<label>Libellé <input type="text" name="label" value=""></label>'
      || '<button type="submit">Ajouter</button>'
      || '</form></details>';

    -- Actions brouillon
    v_body := v_body || '<div class="grid">'
      || format('<a href="%s" role="button" class="outline">Modifier</a>', pgv.call_ref('get_entry_form', jsonb_build_object('p_id', p_id)))
      || pgv.action('post_entry_post', 'Valider', jsonb_build_object('id', p_id), 'Valider cette écriture ? Elle deviendra immutable.')
      || pgv.action('post_entry_delete', 'Supprimer', jsonb_build_object('id', p_id), 'Supprimer ce brouillon ?', 'danger')
      || '</div>';
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_entry(integer) IS 'Fiche écriture : détail + lignes + formulaire ajout ligne si brouillon';

CREATE OR REPLACE FUNCTION ledger.get_entry_form(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_entry record;
  v_body text;
  v_title text;
BEGIN
  IF p_id IS NOT NULL THEN
    SELECT * INTO v_entry FROM ledger.journal_entry WHERE id = p_id;
    IF NOT FOUND THEN RETURN pgv.empty('Écriture introuvable'); END IF;
    IF v_entry.posted THEN RETURN pgv.alert('Écriture validée : modification impossible.', 'danger'); END IF;
    v_title := 'Modifier ' || v_entry.reference;
  ELSE
    v_title := 'Nouvelle écriture';
  END IF;

  v_body := pgv.breadcrumb(VARIADIC ARRAY[
    'Écritures', pgv.call_ref('get_entries'),
    v_title
  ]);

  v_body := v_body || '<form data-rpc="post_entry_save">';

  IF p_id IS NOT NULL THEN
    v_body := v_body || '<input type="hidden" name="id" value="' || p_id || '">';
  END IF;

  v_body := v_body
    || '<label>Date <input type="date" name="entry_date" value="'
      || CASE WHEN p_id IS NOT NULL THEN to_char(v_entry.entry_date, 'YYYY-MM-DD') ELSE to_char(CURRENT_DATE, 'YYYY-MM-DD') END
      || '" required></label>'
    || '<label>Référence <input type="text" name="reference" value="'
      || CASE WHEN p_id IS NOT NULL THEN pgv.esc(v_entry.reference) ELSE '' END
      || '" required placeholder="EX: ACH-001"></label>'
    || '<label>Description <input type="text" name="description" value="'
      || CASE WHEN p_id IS NOT NULL THEN pgv.esc(v_entry.description) ELSE '' END
      || '" required placeholder="Achat matériaux chantier X"></label>'
    || '<button type="submit">Enregistrer</button>'
    || '</form>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_entry_form(integer) IS 'Formulaire création/édition écriture comptable';

CREATE OR REPLACE FUNCTION ledger.get_exercice(p_year integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_year integer;
  v_start date;
  v_end date;
  v_body text;
  v_exercice record;
  v_total_revenue numeric;
  v_total_expense numeric;
  v_resultat numeric;
  v_entry_count integer;
  v_draft_count integer;
BEGIN
  v_year := coalesce(p_year, extract(year FROM CURRENT_DATE)::integer);
  v_start := make_date(v_year, 1, 1);
  v_end := make_date(v_year, 12, 31);

  v_body := pgv.breadcrumb(VARIADIC ARRAY['Exercice ' || v_year]);

  -- Year selector
  v_body := v_body || '<div class="grid">'
    || format('<a href="%s" role="button" class="outline">%s</a>', pgv.call_ref('get_exercice', jsonb_build_object('p_year', v_year - 1)), (v_year - 1)::text)
    || format('<a href="%s" role="button">%s</a>', pgv.call_ref('get_exercice', jsonb_build_object('p_year', v_year)), v_year::text)
    || format('<a href="%s" role="button" class="outline">%s</a>', pgv.call_ref('get_exercice', jsonb_build_object('p_year', v_year + 1)), (v_year + 1)::text)
    || '</div>';

  -- Exercice status
  SELECT * INTO v_exercice FROM ledger.exercice WHERE year = v_year;

  -- Compute totals from posted entries
  SELECT coalesce(sum(CASE WHEN a.type = 'revenue' THEN el.credit - el.debit ELSE 0 END), 0),
         coalesce(sum(CASE WHEN a.type = 'expense' THEN el.debit - el.credit ELSE 0 END), 0)
    INTO v_total_revenue, v_total_expense
    FROM ledger.entry_line el
    JOIN ledger.account a ON a.id = el.account_id
    JOIN ledger.journal_entry je ON je.id = el.journal_entry_id
   WHERE je.posted = true
     AND je.entry_date >= v_start AND je.entry_date <= v_end;

  v_resultat := v_total_revenue - v_total_expense;

  SELECT count(*), count(*) FILTER (WHERE NOT posted)
    INTO v_entry_count, v_draft_count
    FROM ledger.journal_entry
   WHERE entry_date >= v_start AND entry_date <= v_end;

  -- Stats
  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.stat('Statut',
      CASE WHEN v_exercice.closed THEN pgv.badge('Clôturé', 'success')
           ELSE pgv.badge('Ouvert', 'warning') END),
    pgv.stat('Produits', to_char(v_total_revenue, 'FM999 990.00') || ' €'),
    pgv.stat('Charges', to_char(v_total_expense, 'FM999 990.00') || ' €'),
    pgv.stat('Résultat', to_char(v_resultat, 'FM999 990.00') || ' €',
      CASE WHEN v_resultat >= 0 THEN 'Bénéfice' ELSE 'Déficit' END)
  ]);

  -- Entries summary
  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.stat('Écritures', v_entry_count::text),
    pgv.stat('Brouillons', v_draft_count::text,
      CASE WHEN v_draft_count > 0 THEN 'À valider avant clôture' ELSE NULL END)
  ]);

  -- Links
  v_body := v_body || '<div class="grid">'
    || format('<a href="%s" role="button" class="outline">Balance de vérification</a>', pgv.call_ref('get_balance', jsonb_build_object('p_year', v_year)))
    || format('<a href="%s" role="button" class="outline">Bilan P&amp;L</a>', pgv.call_ref('get_bilan', jsonb_build_object('p_year', v_year)))
    || '</div>';

  -- Clôture action
  IF NOT coalesce(v_exercice.closed, false) THEN
    v_body := v_body || pgv.action(
      'Clôturer l''exercice ' || v_year,
      'post_cloture',
      jsonb_build_object('year', v_year),
      'Clôturer définitivement l''exercice ' || v_year || ' ? Cette action est irréversible.'
    );
  ELSE
    v_body := v_body || '<p>Clôturé le '
      || to_char(v_exercice.closed_at, 'DD/MM/YYYY à HH24:MI')
      || ' — résultat enregistré : ' || to_char(v_exercice.result, 'FM999 990.00') || ' €</p>';
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_exercice(integer) IS 'Vue synthétique exercice : produits, charges, résultat, statut (ouvert/clos), action clôture';

CREATE OR REPLACE FUNCTION ledger.get_grand_livre(p_account_id integer, p_year integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_account record;
  v_year integer;
  v_start date;
  v_end date;
  v_body text;
  v_rows text[];
  v_cumul numeric := 0;
  v_total_debit numeric := 0;
  v_total_credit numeric := 0;
  r record;
BEGIN
  SELECT * INTO v_account FROM ledger.account WHERE id = p_account_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'Compte % introuvable', p_account_id; END IF;

  v_year := coalesce(p_year, extract(year FROM CURRENT_DATE)::integer);
  v_start := make_date(v_year, 1, 1);
  v_end := make_date(v_year, 12, 31);

  v_body := pgv.breadcrumb(VARIADIC ARRAY[
    format('<a href="%s">Balance</a>', pgv.call_ref('get_balance', jsonb_build_object('p_year', v_year))),
    v_account.code || ' — ' || v_account.label
  ]);

  -- Year selector
  v_body := v_body || '<div class="grid">'
    || format('<a href="%s" role="button" class="outline">%s</a>', pgv.call_ref('get_grand_livre', jsonb_build_object('p_account_id', p_account_id, 'p_year', v_year - 1)), (v_year - 1)::text)
    || format('<a href="%s" role="button">%s</a>', pgv.call_ref('get_grand_livre', jsonb_build_object('p_account_id', p_account_id, 'p_year', v_year)), v_year::text)
    || format('<a href="%s" role="button" class="outline">%s</a>', pgv.call_ref('get_grand_livre', jsonb_build_object('p_account_id', p_account_id, 'p_year', v_year + 1)), (v_year + 1)::text)
    || '</div>';

  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT je.id AS entry_id, je.entry_date, je.reference, el.label,
           el.debit, el.credit
      FROM ledger.entry_line el
      JOIN ledger.journal_entry je ON je.id = el.journal_entry_id
     WHERE el.account_id = p_account_id
       AND je.posted = true
       AND je.entry_date >= v_start AND je.entry_date <= v_end
     ORDER BY je.entry_date, je.id
  LOOP
    v_cumul := v_cumul + r.debit - r.credit;
    v_total_debit := v_total_debit + r.debit;
    v_total_credit := v_total_credit + r.credit;
    v_rows := v_rows || ARRAY[
      to_char(r.entry_date, 'DD/MM/YYYY'),
      format('<a href="%s">%s</a>', pgv.call_ref('get_entry', jsonb_build_object('p_id', r.entry_id)), pgv.esc(r.reference)),
      pgv.esc(r.label),
      CASE WHEN r.debit > 0 THEN to_char(r.debit, 'FM999 990.00') ELSE '' END,
      CASE WHEN r.credit > 0 THEN to_char(r.credit, 'FM999 990.00') ELSE '' END,
      to_char(v_cumul, 'FM999 990.00')
    ];
  END LOOP;

  -- Stats
  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.stat('Total débit', to_char(v_total_debit, 'FM999 990.00') || ' €'),
    pgv.stat('Total crédit', to_char(v_total_credit, 'FM999 990.00') || ' €'),
    pgv.stat('Solde', to_char(v_cumul, 'FM999 990.00') || ' €')
  ]);

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucun mouvement sur ' || v_year, 'Ce compte n''a pas d''écriture validée sur la période.');
  ELSE
    v_body := v_body || pgv.md_table(
      ARRAY['Date', 'Référence', 'Libellé', 'Débit', 'Crédit', 'Solde cumulé'],
      v_rows, 20
    );
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_grand_livre(integer,integer) IS 'Grand livre : détail des écritures d''un compte avec solde cumulé, filtre par année';

CREATE OR REPLACE FUNCTION ledger.get_index()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_body text;
  v_solde_banque numeric;
  v_ca_mois numeric;
  v_charges_mois numeric;
  v_resultat numeric;
  v_month_start date;
  v_month_end date;
  v_rows text[];
  r record;
BEGIN
  v_month_start := date_trunc('month', CURRENT_DATE)::date;
  v_month_end := (date_trunc('month', CURRENT_DATE) + interval '1 month' - interval '1 day')::date;

  -- KPIs
  SELECT ledger._account_balance(a.id) INTO v_solde_banque
    FROM ledger.account a WHERE a.code = '512';

  v_ca_mois := ledger._period_total('revenue', v_month_start, v_month_end);
  v_charges_mois := ledger._period_total('expense', v_month_start, v_month_end);
  v_resultat := coalesce(v_ca_mois, 0) - coalesce(v_charges_mois, 0);

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat('Solde banque', to_char(coalesce(v_solde_banque, 0), 'FM999 990.00') || ' €'),
    pgv.stat('CA du mois', to_char(coalesce(v_ca_mois, 0), 'FM999 990.00') || ' €'),
    pgv.stat('Charges du mois', to_char(coalesce(v_charges_mois, 0), 'FM999 990.00') || ' €'),
    pgv.stat('Résultat', to_char(v_resultat, 'FM999 990.00') || ' €')
  ]);

  -- Écritures récentes
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT je.id, je.entry_date, je.reference, je.description, je.posted,
           coalesce(sum(el.debit), 0) AS total_debit
      FROM ledger.journal_entry je
      LEFT JOIN ledger.entry_line el ON el.journal_entry_id = je.id
     GROUP BY je.id
     ORDER BY je.entry_date DESC, je.id DESC
     LIMIT 10
  LOOP
    v_rows := v_rows || ARRAY[
      to_char(r.entry_date, 'DD/MM/YYYY'),
      format('<a href="%s">%s</a>', pgv.call_ref('get_entry', jsonb_build_object('p_id', r.id)), pgv.esc(r.reference)),
      pgv.esc(r.description),
      to_char(r.total_debit, 'FM999 990.00') || ' €',
      CASE WHEN r.posted THEN pgv.badge('Validée', 'success') ELSE pgv.badge('Brouillon', 'warning') END
    ];
  END LOOP;

  v_body := v_body || pgv.tabs(VARIADIC ARRAY[
    'Écritures récentes',
    CASE WHEN array_length(v_rows, 1) IS NULL
      THEN pgv.empty('Aucune écriture', 'Créez votre première écriture.')
      ELSE pgv.md_table(ARRAY['Date', 'Référence', 'Description', 'Montant', 'Statut'], v_rows)
    END
  ]);

  v_body := v_body || format('<p><a href="%s" role="button">Nouvelle écriture</a></p>', pgv.call_ref('get_entry_form'));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_index() IS 'Dashboard comptabilité : KPIs (banque, CA, charges, résultat) + écritures récentes';

CREATE OR REPLACE FUNCTION ledger.get_tva(p_year integer DEFAULT NULL::integer, p_quarter integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_year integer;
  v_quarter integer;
  v_start date;
  v_end date;
  v_collectee numeric;
  v_deductible numeric;
  v_solde numeric;
  v_body text;
  v_rows text[];
  r record;
BEGIN
  v_year := coalesce(p_year, extract(year FROM CURRENT_DATE)::integer);
  v_quarter := coalesce(p_quarter, extract(quarter FROM CURRENT_DATE)::integer);

  v_start := make_date(v_year, (v_quarter - 1) * 3 + 1, 1);
  v_end := (v_start + interval '3 months' - interval '1 day')::date;

  v_body := pgv.breadcrumb(VARIADIC ARRAY['TVA']);

  -- Sélecteur période
  v_body := v_body || '<div class="grid">'
    || format('<a href="%s" role="button" class="outline">T1</a>', pgv.call_ref('get_tva', jsonb_build_object('p_year', v_year, 'p_quarter', 1)))
    || format('<a href="%s" role="button" class="outline">T2</a>', pgv.call_ref('get_tva', jsonb_build_object('p_year', v_year, 'p_quarter', 2)))
    || format('<a href="%s" role="button" class="outline">T3</a>', pgv.call_ref('get_tva', jsonb_build_object('p_year', v_year, 'p_quarter', 3)))
    || format('<a href="%s" role="button" class="outline">T4</a>', pgv.call_ref('get_tva', jsonb_build_object('p_year', v_year, 'p_quarter', 4)))
    || '</div>';

  v_body := v_body || '<p>Période : T' || v_quarter || ' ' || v_year
    || ' (' || to_char(v_start, 'DD/MM/YYYY') || ' — ' || to_char(v_end, 'DD/MM/YYYY') || ')</p>';

  -- TVA collectée (4457) = SUM credit - SUM debit sur la période
  SELECT coalesce(sum(el.credit) - sum(el.debit), 0) INTO v_collectee
    FROM ledger.entry_line el
    JOIN ledger.journal_entry je ON je.id = el.journal_entry_id
    JOIN ledger.account a ON a.id = el.account_id
   WHERE a.code = '4457' AND je.posted = true
     AND je.entry_date >= v_start AND je.entry_date <= v_end;

  -- TVA déductible (4456) = SUM debit - SUM credit sur la période
  SELECT coalesce(sum(el.debit) - sum(el.credit), 0) INTO v_deductible
    FROM ledger.entry_line el
    JOIN ledger.journal_entry je ON je.id = el.journal_entry_id
    JOIN ledger.account a ON a.id = el.account_id
   WHERE a.code = '4456' AND je.posted = true
     AND je.entry_date >= v_start AND je.entry_date <= v_end;

  v_solde := v_collectee - v_deductible;

  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.stat('TVA collectée', to_char(v_collectee, 'FM999 990.00') || ' €'),
    pgv.stat('TVA déductible', to_char(v_deductible, 'FM999 990.00') || ' €'),
    pgv.stat(
      CASE WHEN v_solde >= 0 THEN 'TVA à reverser' ELSE 'Crédit de TVA' END,
      to_char(abs(v_solde), 'FM999 990.00') || ' €'
    )
  ]);

  -- Détail par écriture
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT je.entry_date, je.reference, je.id AS entry_id,
           el.debit, el.credit, a.code, a.label AS account_label
      FROM ledger.entry_line el
      JOIN ledger.journal_entry je ON je.id = el.journal_entry_id
      JOIN ledger.account a ON a.id = el.account_id
     WHERE a.code IN ('4456', '4457') AND je.posted = true
       AND je.entry_date >= v_start AND je.entry_date <= v_end
     ORDER BY je.entry_date, je.id
  LOOP
    v_rows := v_rows || ARRAY[
      to_char(r.entry_date, 'DD/MM/YYYY'),
      format('<a href="%s">%s</a>', pgv.call_ref('get_entry', jsonb_build_object('p_id', r.entry_id)), pgv.esc(r.reference)),
      r.code || ' ' || pgv.esc(r.account_label),
      CASE WHEN r.debit > 0 THEN to_char(r.debit, 'FM999 990.00') ELSE '' END,
      CASE WHEN r.credit > 0 THEN to_char(r.credit, 'FM999 990.00') ELSE '' END
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h4>Détail mouvements TVA</h4>'
      || pgv.md_table(ARRAY['Date', 'Référence', 'Compte', 'Débit', 'Crédit'], v_rows);
  ELSE
    v_body := v_body || pgv.empty('Aucun mouvement TVA sur la période');
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_tva(integer,integer) IS 'Déclaration TVA : collectée, déductible, solde. Filtre par trimestre/année.';

CREATE OR REPLACE FUNCTION ledger.nav_items()
 RETURNS jsonb
 LANGUAGE sql
AS $function$
SELECT '[
    {"href":"/","label":"Tableau de bord","icon":"home"},
    {"href":"/entries","label":"Écritures","icon":"list"},
    {"href":"/accounts","label":"Plan comptable","icon":"book"},
    {"href":"/balance","label":"Balance","icon":"scale"},
    {"href":"/exercice","label":"Exercice","icon":"calendar"},
    {"href":"/tva","label":"TVA","icon":"percent"},
    {"href":"/bilan","label":"Bilan","icon":"bar-chart"}
  ]'::jsonb;
$function$;
COMMENT ON FUNCTION ledger.nav_items() IS 'Navigation items for Ledger module';

CREATE OR REPLACE FUNCTION ledger.post_cloture(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_year integer;
  v_start date;
  v_end date;
  v_total_revenue numeric;
  v_total_expense numeric;
  v_resultat numeric;
  v_draft_count integer;
  v_entry_id integer;
  v_account_120 integer;
BEGIN
  v_year := (p_data->>'year')::integer;
  IF v_year IS NULL THEN RAISE EXCEPTION 'Année requise'; END IF;

  -- Guard: pas de double clôture
  IF EXISTS (SELECT 1 FROM ledger.exercice WHERE year = v_year AND closed = true) THEN
    RETURN '<template data-toast="error">L''exercice ' || v_year || ' est déjà clôturé</template>';
  END IF;

  v_start := make_date(v_year, 1, 1);
  v_end := make_date(v_year, 12, 31);

  -- Guard: pas d'écritures brouillon sur la période
  SELECT count(*) INTO v_draft_count
    FROM ledger.journal_entry
   WHERE posted = false
     AND entry_date >= v_start AND entry_date <= v_end;

  IF v_draft_count > 0 THEN
    RETURN '<template data-toast="error">' || v_draft_count || ' écriture(s) brouillon sur ' || v_year || ' — validez-les avant clôture</template>';
  END IF;

  -- Calcul résultat : produits - charges (écritures postées)
  SELECT coalesce(sum(CASE WHEN a.type = 'revenue' THEN el.credit - el.debit ELSE 0 END), 0),
         coalesce(sum(CASE WHEN a.type = 'expense' THEN el.debit - el.credit ELSE 0 END), 0)
    INTO v_total_revenue, v_total_expense
    FROM ledger.entry_line el
    JOIN ledger.account a ON a.id = el.account_id
    JOIN ledger.journal_entry je ON je.id = el.journal_entry_id
   WHERE je.posted = true
     AND je.entry_date >= v_start AND je.entry_date <= v_end;

  v_resultat := v_total_revenue - v_total_expense;

  -- Écriture de résultat (compte 120)
  SELECT id INTO v_account_120 FROM ledger.account WHERE code = '120';
  IF v_account_120 IS NULL THEN RAISE EXCEPTION 'Compte 120 (Résultat) introuvable dans le plan comptable'; END IF;

  INSERT INTO ledger.journal_entry (entry_date, reference, description)
  VALUES (v_end, 'CLO-' || v_year, 'Clôture exercice ' || v_year || ' — résultat ' || to_char(v_resultat, 'FM999 990.00') || ' €')
  RETURNING id INTO v_entry_id;

  -- Zero out revenue accounts: DEBIT (revenue normally has credit balance)
  INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
  SELECT v_entry_id, a.id, coalesce(sum(el.credit - el.debit), 0), 0, 'Solde ' || a.label
    FROM ledger.account a
    JOIN ledger.entry_line el ON el.account_id = a.id
    JOIN ledger.journal_entry je ON je.id = el.journal_entry_id
   WHERE a.type = 'revenue' AND je.posted = true
     AND je.entry_date >= v_start AND je.entry_date <= v_end
     AND je.id <> v_entry_id
   GROUP BY a.id, a.label
  HAVING coalesce(sum(el.credit - el.debit), 0) <> 0;

  -- Zero out expense accounts: CREDIT (expense normally has debit balance)
  INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
  SELECT v_entry_id, a.id, 0, coalesce(sum(el.debit - el.credit), 0), 'Solde ' || a.label
    FROM ledger.account a
    JOIN ledger.entry_line el ON el.account_id = a.id
    JOIN ledger.journal_entry je ON je.id = el.journal_entry_id
   WHERE a.type = 'expense' AND je.posted = true
     AND je.entry_date >= v_start AND je.entry_date <= v_end
     AND je.id <> v_entry_id
   GROUP BY a.id, a.label
  HAVING coalesce(sum(el.debit - el.credit), 0) <> 0;

  -- Result to account 120: credit if benefit, debit if deficit
  IF v_resultat >= 0 THEN
    INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
    VALUES (v_entry_id, v_account_120, 0, v_resultat, 'Résultat bénéficiaire ' || v_year);
  ELSE
    INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
    VALUES (v_entry_id, v_account_120, abs(v_resultat), 0, 'Résultat déficitaire ' || v_year);
  END IF;

  -- Valider l'écriture de clôture
  UPDATE ledger.journal_entry SET posted = true WHERE id = v_entry_id;

  -- Marquer l'exercice clos
  INSERT INTO ledger.exercice (year, closed, closed_at, result)
  VALUES (v_year, true, now(), v_resultat)
  ON CONFLICT ON CONSTRAINT exercice_tenant_year_key
  DO UPDATE SET closed = true, closed_at = now(), result = v_resultat;

  RETURN '<template data-toast="success">Exercice ' || v_year || ' clôturé — résultat : ' || to_char(v_resultat, 'FM999 990.00') || ' €</template>'
    || '<template data-redirect="' || pgv.call_ref('get_exercice', jsonb_build_object('p_year', v_year)) || '"></template>';
END;
$function$;
COMMENT ON FUNCTION ledger.post_cloture(jsonb) IS 'Clôture d''exercice : vérifie écritures postées, calcule résultat, crée écriture de résultat (120), marque exercice clos';

CREATE OR REPLACE FUNCTION ledger.post_entry_delete(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id integer;
BEGIN
  v_id := (p_data->>'id')::integer;

  IF NOT EXISTS (SELECT 1 FROM ledger.journal_entry WHERE id = v_id AND NOT posted) THEN
    RAISE EXCEPTION 'Écriture introuvable ou déjà validée — suppression impossible';
  END IF;

  DELETE FROM ledger.journal_entry WHERE id = v_id;

  RETURN '<template data-toast="success">Écriture supprimée</template>'
    || '<template data-redirect="' || pgv.call_ref('get_entries') || '"></template>';
END;
$function$;
COMMENT ON FUNCTION ledger.post_entry_delete(jsonb) IS 'Supprimer une écriture brouillon. RAISE si validée.';

CREATE OR REPLACE FUNCTION ledger.post_entry_post(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id integer;
BEGIN
  v_id := (p_data->>'id')::integer;

  IF NOT EXISTS (SELECT 1 FROM ledger.journal_entry WHERE id = v_id AND NOT posted) THEN
    RAISE EXCEPTION 'Écriture introuvable ou déjà validée';
  END IF;

  IF NOT ledger._entry_balanced(v_id) THEN
    RAISE EXCEPTION 'Écriture déséquilibrée : impossible de valider';
  END IF;

  UPDATE ledger.journal_entry SET posted = true WHERE id = v_id;

  RETURN '<template data-toast="success">Écriture validée</template>'
    || '<template data-redirect="' || pgv.call_ref('get_entry', jsonb_build_object('p_id', v_id)) || '"></template>';
END;
$function$;
COMMENT ON FUNCTION ledger.post_entry_post(jsonb) IS 'Valider une écriture brouillon (posted=true). RAISE si déséquilibrée.';

CREATE OR REPLACE FUNCTION ledger.post_entry_save(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id integer;
BEGIN
  IF p_data->>'id' IS NOT NULL THEN
    v_id := (p_data->>'id')::integer;
    IF NOT EXISTS (SELECT 1 FROM ledger.journal_entry WHERE id = v_id AND NOT posted) THEN
      RAISE EXCEPTION 'Seuls les brouillons sont modifiables';
    END IF;
    UPDATE ledger.journal_entry SET
      entry_date = (p_data->>'entry_date')::date,
      reference = p_data->>'reference',
      description = p_data->>'description'
    WHERE id = v_id;
  ELSE
    INSERT INTO ledger.journal_entry (entry_date, reference, description)
    VALUES (
      coalesce((p_data->>'entry_date')::date, CURRENT_DATE),
      p_data->>'reference',
      p_data->>'description'
    ) RETURNING id INTO v_id;
  END IF;

  RETURN '<template data-toast="success">Écriture enregistrée</template>'
    || '<template data-redirect="' || pgv.call_ref('get_entry', jsonb_build_object('p_id', v_id)) || '"></template>';
END;
$function$;
COMMENT ON FUNCTION ledger.post_entry_save(jsonb) IS 'Créer ou modifier une écriture brouillon (upsert)';

CREATE OR REPLACE FUNCTION ledger.post_from_facture(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_facture_id integer;
  v_facture record;
  v_entry_id integer;
  v_total_ht numeric(12,2);
  v_total_tva numeric(12,2);
  v_total_ttc numeric(12,2);
  v_account_411 integer;
  v_account_4457 integer;
  v_account_706 integer;
BEGIN
  v_facture_id := (p_data->>'facture_id')::integer;

  SELECT * INTO v_facture FROM quote.facture WHERE id = v_facture_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'Facture % introuvable', v_facture_id; END IF;

  -- Guard: doublon interdit
  IF EXISTS (SELECT 1 FROM ledger.journal_entry WHERE facture_id = v_facture_id) THEN
    RETURN '<template data-toast="error">Cette facture a déjà une écriture comptable</template>';
  END IF;

  -- Totaux
  SELECT coalesce(sum(round(l.quantite * l.prix_unitaire, 2)), 0),
         coalesce(sum(round(l.quantite * l.prix_unitaire * l.tva_rate / 100, 2)), 0)
    INTO v_total_ht, v_total_tva
    FROM quote.ligne l
   WHERE l.facture_id = v_facture_id;

  v_total_ttc := v_total_ht + v_total_tva;

  IF v_total_ttc = 0 THEN RAISE EXCEPTION 'Facture sans montant'; END IF;

  -- Resolve account IDs
  SELECT id INTO v_account_411 FROM ledger.account WHERE code = '411';
  SELECT id INTO v_account_4457 FROM ledger.account WHERE code = '4457';
  SELECT id INTO v_account_706 FROM ledger.account WHERE code = '706';

  -- Create journal entry with facture_id
  INSERT INTO ledger.journal_entry (entry_date, reference, description, facture_id)
  VALUES (
    coalesce(v_facture.paid_at::date, CURRENT_DATE),
    'FAC-' || v_facture.numero,
    'Facture ' || v_facture.numero || ' — ' || v_facture.objet,
    v_facture_id
  ) RETURNING id INTO v_entry_id;

  -- 411 Clients — débit TTC
  INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
  VALUES (v_entry_id, v_account_411, v_total_ttc, 0, 'Client facture ' || v_facture.numero);

  -- 4457 TVA collectée — crédit TVA
  IF v_total_tva > 0 THEN
    INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
    VALUES (v_entry_id, v_account_4457, 0, v_total_tva, 'TVA collectée facture ' || v_facture.numero);
  END IF;

  -- 706 Prestations — crédit HT
  INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
  VALUES (v_entry_id, v_account_706, 0, v_total_ht, 'Prestation facture ' || v_facture.numero);

  RETURN '<template data-toast="success">Écriture créée depuis facture ' || pgv.esc(v_facture.numero) || '</template>'
    || '<template data-redirect="' || pgv.call_ref('get_entry', jsonb_build_object('p_id', v_entry_id)) || '"></template>';
END;
$function$;
COMMENT ON FUNCTION ledger.post_from_facture(jsonb) IS 'Créer écriture comptable de vente depuis une facture quote (411/4457/706-707). Brouillon pour review. Une facture = une écriture max.';

CREATE OR REPLACE FUNCTION ledger.post_line_add(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_entry_id integer;
  v_account_id integer;
  v_debit numeric(12,2);
  v_credit numeric(12,2);
BEGIN
  v_entry_id := (p_data->>'entry_id')::integer;

  IF NOT EXISTS (SELECT 1 FROM ledger.journal_entry WHERE id = v_entry_id AND NOT posted) THEN
    RAISE EXCEPTION 'Écriture introuvable ou déjà validée';
  END IF;

  -- Resolve account by id or code
  IF p_data->>'account_id' IS NOT NULL THEN
    v_account_id := (p_data->>'account_id')::integer;
  ELSIF p_data->>'account_code' IS NOT NULL THEN
    SELECT id INTO v_account_id FROM ledger.account WHERE code = p_data->>'account_code';
    IF NOT FOUND THEN RAISE EXCEPTION 'Compte % introuvable', p_data->>'account_code'; END IF;
  ELSE
    RAISE EXCEPTION 'account_id ou account_code requis';
  END IF;

  v_debit := coalesce((p_data->>'debit')::numeric, 0);
  v_credit := coalesce((p_data->>'credit')::numeric, 0);

  IF v_debit = 0 AND v_credit = 0 THEN
    RAISE EXCEPTION 'Débit ou crédit doit être > 0';
  END IF;

  INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
  VALUES (v_entry_id, v_account_id, v_debit, v_credit, coalesce(p_data->>'label', ''));

  RETURN '<template data-toast="success">Ligne ajoutée</template>'
    || '<template data-redirect="' || pgv.call_ref('get_entry', jsonb_build_object('p_id', v_entry_id)) || '"></template>';
END;
$function$;
COMMENT ON FUNCTION ledger.post_line_add(jsonb) IS 'Ajouter une ligne à une écriture brouillon';

CREATE OR REPLACE FUNCTION ledger.post_line_delete(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id integer;
  v_entry_id integer;
BEGIN
  v_id := (p_data->>'id')::integer;
  v_entry_id := (p_data->>'entry_id')::integer;

  IF NOT EXISTS (SELECT 1 FROM ledger.journal_entry WHERE id = v_entry_id AND NOT posted) THEN
    RAISE EXCEPTION 'Écriture introuvable ou déjà validée';
  END IF;

  DELETE FROM ledger.entry_line WHERE id = v_id AND journal_entry_id = v_entry_id;

  RETURN '<template data-toast="success">Ligne supprimée</template>'
    || '<template data-redirect="' || pgv.call_ref('get_entry', jsonb_build_object('p_id', v_entry_id)) || '"></template>';
END;
$function$;
COMMENT ON FUNCTION ledger.post_line_delete(jsonb) IS 'Supprimer une ligne d''écriture brouillon';

GRANT USAGE ON SCHEMA ledger TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA ledger TO web_anon;

-- Schema: ledger_ut
CREATE SCHEMA IF NOT EXISTS ledger_ut;

CREATE OR REPLACE FUNCTION ledger_ut.test_account_balance()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_entry_id integer;
  v_acc_512 integer;
  v_acc_706 integer;
  v_html text;
BEGIN
  -- Cleanup: unpost first, then delete
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;

  SELECT id INTO v_acc_512 FROM ledger.account WHERE code = '512';
  SELECT id INTO v_acc_706 FROM ledger.account WHERE code = '706';

  -- Create and post a balanced entry
  INSERT INTO ledger.journal_entry (entry_date, reference, description)
  VALUES (CURRENT_DATE, 'TEST-BAL', 'Test balance')
  RETURNING id INTO v_entry_id;

  INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit)
  VALUES (v_entry_id, v_acc_512, 1000, 0),
         (v_entry_id, v_acc_706, 0, 1000);

  UPDATE ledger.journal_entry SET posted = true WHERE id = v_entry_id;

  -- Verify via get_account page
  v_html := ledger.get_account(v_acc_512);
  RETURN NEXT ok(v_html LIKE '%1 000.00%', 'Banque (asset) affiche solde 1 000.00');

  v_html := ledger.get_account(v_acc_706);
  RETURN NEXT ok(v_html LIKE '%1 000.00%', 'Prestations (revenue) affiche solde 1 000.00');

  v_html := ledger.get_index();
  RETURN NEXT ok(v_html LIKE '%1 000.00%', 'Dashboard affiche solde banque');

  -- Cleanup
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;
END;
$function$;
COMMENT ON FUNCTION ledger_ut.test_account_balance() IS 'Test soldes corrects selon type (débiteur/créditeur) via posted entries';

CREATE OR REPLACE FUNCTION ledger_ut.test_balance()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
  v_entry_id integer;
BEGIN
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;

  -- Create a posted entry
  INSERT INTO ledger.journal_entry (entry_date, reference, description)
  VALUES ('2026-01-15', 'BAL-TEST', 'Test balance')
  RETURNING id INTO v_entry_id;

  INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
  VALUES
    (v_entry_id, (SELECT id FROM ledger.account WHERE code = '411'), 1200.00, 0, 'Client'),
    (v_entry_id, (SELECT id FROM ledger.account WHERE code = '706'), 0, 1200.00, 'Prestation');
  UPDATE ledger.journal_entry SET posted = true WHERE id = v_entry_id;

  v_html := ledger.get_balance(2026);
  RETURN NEXT ok(length(v_html) > 100, 'get_balance() retourne du HTML substantiel');
  RETURN NEXT ok(v_html LIKE '%411%', 'Balance contient compte 411');
  RETURN NEXT ok(v_html LIKE '%706%', 'Balance contient compte 706');
  RETURN NEXT ok(v_html LIKE '%quilibre OK%', 'Balance affiche Équilibre OK');

  -- Cleanup
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;
END;
$function$;
COMMENT ON FUNCTION ledger_ut.test_balance() IS 'Test balance de vérification : total débit = total crédit';

CREATE OR REPLACE FUNCTION ledger_ut.test_entry_balanced()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_entry_id integer;
BEGIN
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;

  PERFORM ledger.post_entry_save(jsonb_build_object(
    'reference', 'TEST-EQ', 'description', 'Test équilibre'
  ));
  SELECT id INTO v_entry_id FROM ledger.journal_entry ORDER BY id DESC LIMIT 1;

  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry_id, 'account_code', '512', 'debit', 100, 'credit', 0
  ));

  RETURN NEXT throws_ok(
    format('SELECT ledger.post_entry_post(''{"id":%s}''::jsonb)', v_entry_id),
    'Écriture déséquilibrée : impossible de valider'
  );

  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry_id, 'account_code', '601', 'debit', 0, 'credit', 100
  ));

  RETURN NEXT lives_ok(
    format('SELECT ledger.post_entry_post(''{"id":%s}''::jsonb)', v_entry_id),
    'Écriture équilibrée : validation OK'
  );

  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;
END;
$function$;
COMMENT ON FUNCTION ledger_ut.test_entry_balanced() IS 'Test validation impossible si écriture déséquilibrée';

CREATE OR REPLACE FUNCTION ledger_ut.test_extourne()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_entry1_id integer;
  v_entry2_id integer;
  v_html text;
  v_acc_512 integer;
BEGIN
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;

  SELECT id INTO v_acc_512 FROM ledger.account WHERE code = '512';

  -- Écriture originale : achat 601 débit 500, 512 crédit 500
  PERFORM ledger.post_entry_save(jsonb_build_object(
    'reference', 'TEST-EXT1', 'description', 'Achat original'
  ));
  SELECT id INTO v_entry1_id FROM ledger.journal_entry ORDER BY id DESC LIMIT 1;

  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry1_id, 'account_code', '601', 'debit', 500, 'credit', 0
  ));
  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry1_id, 'account_code', '512', 'debit', 0, 'credit', 500
  ));
  PERFORM ledger.post_entry_post(jsonb_build_object('id', v_entry1_id));

  v_html := ledger.get_account(v_acc_512);
  RETURN NEXT ok(v_html LIKE '%500.00%', 'Banque affiche solde après achat');

  -- Extourne : sens inversé
  PERFORM ledger.post_entry_save(jsonb_build_object(
    'reference', 'TEST-EXT2', 'description', 'Extourne achat'
  ));
  SELECT id INTO v_entry2_id FROM ledger.journal_entry WHERE reference = 'TEST-EXT2';

  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry2_id, 'account_code', '512', 'debit', 500, 'credit', 0
  ));
  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry2_id, 'account_code', '601', 'debit', 0, 'credit', 500
  ));
  PERFORM ledger.post_entry_post(jsonb_build_object('id', v_entry2_id));

  v_html := ledger.get_account(v_acc_512);
  RETURN NEXT ok(v_html LIKE '%0.00%', 'Après extourne, solde banque = 0');

  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;
END;
$function$;
COMMENT ON FUNCTION ledger_ut.test_extourne() IS 'Test écriture d''extourne annule bien le solde';

CREATE OR REPLACE FUNCTION ledger_ut.test_from_facture()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_facture_id integer;
  v_entry_id integer;
  v_line_count integer;
  v_total_debit numeric;
  v_total_credit numeric;
BEGIN
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;

  SELECT f.id INTO v_facture_id
    FROM quote.facture f
    JOIN quote.ligne l ON l.facture_id = f.id
   GROUP BY f.id
   HAVING count(*) > 0
   LIMIT 1;

  IF v_facture_id IS NULL THEN
    RETURN NEXT skip('Aucune facture avec lignes dans quote — test ignoré');
    RETURN;
  END IF;

  PERFORM ledger.post_from_facture(jsonb_build_object('facture_id', v_facture_id));

  SELECT id INTO v_entry_id FROM ledger.journal_entry ORDER BY id DESC LIMIT 1;

  SELECT count(*), sum(debit), sum(credit)
    INTO v_line_count, v_total_debit, v_total_credit
    FROM ledger.entry_line WHERE journal_entry_id = v_entry_id;

  RETURN NEXT ok(v_line_count >= 2, 'Écriture facture a >= 2 lignes (a ' || v_line_count || ')');
  RETURN NEXT is(v_total_debit, v_total_credit, 'Écriture facture équilibrée : débit = crédit');

  RETURN NEXT ok(
    EXISTS (SELECT 1 FROM ledger.journal_entry WHERE id = v_entry_id AND reference LIKE 'FAC-%'),
    'Référence commence par FAC-'
  );

  RETURN NEXT ok(
    EXISTS (SELECT 1 FROM ledger.entry_line el JOIN ledger.account a ON a.id = el.account_id
            WHERE el.journal_entry_id = v_entry_id AND a.code = '411' AND el.debit > 0),
    'Ligne 411 Clients en débit'
  );
  RETURN NEXT ok(
    EXISTS (SELECT 1 FROM ledger.entry_line el JOIN ledger.account a ON a.id = el.account_id
            WHERE el.journal_entry_id = v_entry_id AND a.code = '706' AND el.credit > 0),
    'Ligne 706 Prestations en crédit'
  );

  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;
END;
$function$;
COMMENT ON FUNCTION ledger_ut.test_from_facture() IS 'Test écriture générée depuis facture quote correctement ventilée';

CREATE OR REPLACE FUNCTION ledger_ut.test_pages_render()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
  v_entry_id integer;
  v_acc_id integer;
BEGIN
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;
  DELETE FROM ledger.exercice;

  v_html := ledger.get_index();
  RETURN NEXT ok(length(v_html) > 50, 'get_index() retourne du HTML');

  v_html := ledger.get_entries();
  RETURN NEXT ok(length(v_html) > 50, 'get_entries() retourne du HTML');

  v_html := ledger.get_accounts();
  RETURN NEXT ok(length(v_html) > 50, 'get_accounts() retourne du HTML');

  v_html := ledger.get_entry_form();
  RETURN NEXT ok(length(v_html) > 50, 'get_entry_form() retourne du HTML');

  v_html := ledger.get_tva();
  RETURN NEXT ok(length(v_html) > 50, 'get_tva() retourne du HTML');

  v_html := ledger.get_bilan();
  RETURN NEXT ok(length(v_html) > 50, 'get_bilan() retourne du HTML');

  v_html := ledger.get_balance();
  RETURN NEXT ok(length(v_html) > 50, 'get_balance() retourne du HTML');

  v_html := ledger.get_exercice();
  RETURN NEXT ok(length(v_html) > 50, 'get_exercice() retourne du HTML');

  SELECT id INTO v_acc_id FROM ledger.account LIMIT 1;
  v_html := ledger.get_account(v_acc_id);
  RETURN NEXT ok(length(v_html) > 50, 'get_account(id) retourne du HTML');

  v_html := ledger.get_grand_livre(v_acc_id);
  RETURN NEXT ok(length(v_html) > 50, 'get_grand_livre(id) retourne du HTML');

  PERFORM ledger.post_entry_save(jsonb_build_object(
    'reference', 'TEST-PAGE', 'description', 'Test pages'
  ));
  SELECT id INTO v_entry_id FROM ledger.journal_entry ORDER BY id DESC LIMIT 1;
  v_html := ledger.get_entry(v_entry_id);
  RETURN NEXT ok(length(v_html) > 50, 'get_entry(id) retourne du HTML');

  v_html := ledger.get_entry_form(v_entry_id);
  RETURN NEXT ok(length(v_html) > 50, 'get_entry_form(id) retourne du HTML');

  RETURN NEXT ok(ledger.nav_items() IS NOT NULL, 'nav_items() retourne du JSON');
  RETURN NEXT ok(length(ledger.brand()) > 0, 'brand() retourne un label');

  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;
END;
$function$;
COMMENT ON FUNCTION ledger_ut.test_pages_render() IS 'Test toutes les pages retournent du HTML non-vide';

CREATE OR REPLACE FUNCTION ledger_ut.test_post_cloture()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_entry_id integer;
  v_result text;
  v_exercice record;
  v_total_debit numeric;
  v_total_credit numeric;
  v_clo_entry_id integer;
BEGIN
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;
  DELETE FROM ledger.exercice;

  -- Create a revenue entry in 2025
  INSERT INTO ledger.journal_entry (entry_date, reference, description)
  VALUES ('2025-06-15', 'FAC-TEST', 'Facture test clôture')
  RETURNING id INTO v_entry_id;

  INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
  VALUES
    (v_entry_id, (SELECT id FROM ledger.account WHERE code = '411'), 1200.00, 0, 'Client'),
    (v_entry_id, (SELECT id FROM ledger.account WHERE code = '4457'), 0, 200.00, 'TVA'),
    (v_entry_id, (SELECT id FROM ledger.account WHERE code = '706'), 0, 1000.00, 'Prestation');
  UPDATE ledger.journal_entry SET posted = true WHERE id = v_entry_id;

  -- Create an expense entry in 2025
  INSERT INTO ledger.journal_entry (entry_date, reference, description)
  VALUES ('2025-03-10', 'ACH-TEST', 'Achat test clôture')
  RETURNING id INTO v_entry_id;

  INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
  VALUES
    (v_entry_id, (SELECT id FROM ledger.account WHERE code = '601'), 300.00, 0, 'Matériaux'),
    (v_entry_id, (SELECT id FROM ledger.account WHERE code = '512'), 0, 300.00, 'Paiement');
  UPDATE ledger.journal_entry SET posted = true WHERE id = v_entry_id;

  -- Clôturer 2025
  v_result := ledger.post_cloture('{"year": 2025}'::jsonb);
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'Clôture 2025 réussie');

  -- Vérifier exercice
  SELECT * INTO v_exercice FROM ledger.exercice WHERE year = 2025;
  RETURN NEXT ok(v_exercice.closed, 'Exercice 2025 marqué clos');
  RETURN NEXT is(v_exercice.result, 700.00, 'Résultat = 1000 - 300 = 700');

  -- Vérifier écriture de clôture équilibrée
  SELECT id INTO v_clo_entry_id FROM ledger.journal_entry WHERE reference = 'CLO-2025';
  RETURN NEXT ok(v_clo_entry_id IS NOT NULL, 'Écriture CLO-2025 créée');

  SELECT sum(debit), sum(credit)
    INTO v_total_debit, v_total_credit
    FROM ledger.entry_line WHERE journal_entry_id = v_clo_entry_id;
  RETURN NEXT is(v_total_debit, v_total_credit, 'Écriture clôture équilibrée');

  -- Double clôture bloquée
  v_result := ledger.post_cloture('{"year": 2025}'::jsonb);
  RETURN NEXT ok(v_result LIKE '%déjà clôturé%', 'Double clôture bloquée');

  -- Cleanup
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;
  DELETE FROM ledger.exercice;
END;
$function$;
COMMENT ON FUNCTION ledger_ut.test_post_cloture() IS 'Test clôture exercice : résultat correct, double clôture bloquée, écriture de résultat équilibrée';

CREATE OR REPLACE FUNCTION ledger_ut.test_protect_posted()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_entry_id integer;
  v_line_id integer;
BEGIN
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;

  PERFORM ledger.post_entry_save(jsonb_build_object(
    'reference', 'TEST-PROT', 'description', 'Test protection'
  ));
  SELECT id INTO v_entry_id FROM ledger.journal_entry ORDER BY id DESC LIMIT 1;

  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry_id, 'account_code', '512', 'debit', 200, 'credit', 0
  ));
  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry_id, 'account_code', '601', 'debit', 0, 'credit', 200
  ));
  PERFORM ledger.post_entry_post(jsonb_build_object('id', v_entry_id));

  SELECT id INTO v_line_id FROM ledger.entry_line WHERE journal_entry_id = v_entry_id LIMIT 1;

  RETURN NEXT throws_ok(
    format('UPDATE ledger.journal_entry SET description = ''hack'' WHERE id = %s', v_entry_id),
    'Écriture validée : modification interdite (id=' || v_entry_id || ')'
  );

  RETURN NEXT throws_ok(
    format('DELETE FROM ledger.journal_entry WHERE id = %s', v_entry_id),
    'Écriture validée : suppression interdite (id=' || v_entry_id || ')'
  );

  RETURN NEXT throws_ok(
    format('INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit) VALUES (%s, (SELECT id FROM ledger.account WHERE code = ''512''), 10, 0)', v_entry_id),
    'Écriture validée : modification des lignes interdite'
  );

  RETURN NEXT throws_ok(
    format('UPDATE ledger.entry_line SET debit = 999 WHERE id = %s', v_line_id),
    'Écriture validée : modification des lignes interdite'
  );

  RETURN NEXT throws_ok(
    format('DELETE FROM ledger.entry_line WHERE id = %s', v_line_id),
    'Écriture validée : modification des lignes interdite'
  );

  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;
END;
$function$;
COMMENT ON FUNCTION ledger_ut.test_protect_posted() IS 'Test immutabilité : UPDATE/DELETE bloqués sur écriture validée + lignes';

CREATE OR REPLACE FUNCTION ledger_ut.test_tva()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_entry_id integer;
  v_html text;
BEGIN
  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;

  -- Vente avec TVA collectée
  PERFORM ledger.post_entry_save(jsonb_build_object(
    'entry_date', CURRENT_DATE, 'reference', 'TEST-TVA1', 'description', 'Vente prestation'
  ));
  SELECT id INTO v_entry_id FROM ledger.journal_entry WHERE reference = 'TEST-TVA1';

  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry_id, 'account_code', '411', 'debit', 120, 'credit', 0
  ));
  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry_id, 'account_code', '4457', 'debit', 0, 'credit', 20
  ));
  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry_id, 'account_code', '706', 'debit', 0, 'credit', 100
  ));
  PERFORM ledger.post_entry_post(jsonb_build_object('id', v_entry_id));

  -- Achat avec TVA déductible
  PERFORM ledger.post_entry_save(jsonb_build_object(
    'entry_date', CURRENT_DATE, 'reference', 'TEST-TVA2', 'description', 'Achat matériaux'
  ));
  SELECT id INTO v_entry_id FROM ledger.journal_entry WHERE reference = 'TEST-TVA2';

  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry_id, 'account_code', '601', 'debit', 50, 'credit', 0
  ));
  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry_id, 'account_code', '4456', 'debit', 10, 'credit', 0
  ));
  PERFORM ledger.post_line_add(jsonb_build_object(
    'entry_id', v_entry_id, 'account_code', '512', 'debit', 0, 'credit', 60
  ));
  PERFORM ledger.post_entry_post(jsonb_build_object('id', v_entry_id));

  v_html := ledger.get_tva(extract(year FROM CURRENT_DATE)::integer, extract(quarter FROM CURRENT_DATE)::integer);
  RETURN NEXT ok(v_html LIKE '%20.00%', 'TVA collectée = 20.00');
  RETURN NEXT ok(v_html LIKE '%10.00%', 'TVA déductible = 10.00');
  RETURN NEXT ok(v_html LIKE '%reverser%', 'TVA à reverser (solde positif)');

  UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
  DELETE FROM ledger.entry_line;
  DELETE FROM ledger.journal_entry;
END;
$function$;
COMMENT ON FUNCTION ledger_ut.test_tva() IS 'Test déclaration TVA = 4457 - 4456';

GRANT USAGE ON SCHEMA ledger_ut TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA ledger_ut TO web_anon;

-- Schema: ledger_qa
CREATE SCHEMA IF NOT EXISTS ledger_qa;

CREATE OR REPLACE FUNCTION ledger_qa.clean()
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
    UPDATE ledger.journal_entry SET posted = false WHERE posted = true;
    DELETE FROM ledger.entry_line;
    DELETE FROM ledger.journal_entry;
END;
$function$;
COMMENT ON FUNCTION ledger_qa.clean() IS 'Nettoie les données démo du schema ledger';

